MAP
  NAME "Rutland"
  STATUS ON
  EXTENT -180 -90 180 90
  SHAPEPATH "../../layers"

  OUTPUTFORMAT
    NAME "geojson"
    DRIVER "OGR/GEOJSON"
    MIMETYPE "application/json; subtype=geojson"
    FORMATOPTION "STORAGE=stream"
    FORMATOPTION "FORM=SIMPLE"
  END

  LAYER
    NAME "lighting"
    METADATA
      "wfs_title"         "Lighting"
      "wfs_srs"           "EPSG:3857 EPSG:27700"
      "gml_include_items" "unique_id,unit_type"
      "gml_featureid"     "unique_id"
      "wfs_enable_request" "*"
    END
    TYPE POINT
    STATUS ON
    DATA 'rutland/ums_inventory'
    PROJECTION
      "init=epsg:27700"
    END
  END #layer

END #mapfile
